@page "/privacy"
@using Microsoft.AspNetCore.Http
@attribute [Microsoft.AspNetCore.Components.ExcludeFromInteractiveRouting]

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

<p>Your privacy is important to us. This page describes how we handle your data.</p>

@if (HasConsent)
{
    <div class="alert alert-success">
        ✅ You have already accepted cookies.
    </div>
}
else
{
    <div class="alert alert-warning">
        ⚠️ You have not yet accepted cookies.
    </div>
}

@code {
    [CascadingParameter]
    private HttpContext? HttpContext { get; set; }

    private bool HasConsent =>
        HttpContext?.Request.Cookies.ContainsKey("consent") == true;
}

